const items = $input.all();
const filtered = items.filter(item => item.json.drive_folder_id);
if (filtered.length === 0) return [];
return filtered;

const httpRequest = globalThis.helpers.httpRequest;
const SUPABASE_URL = 'PLACEHOLDER_SUPABASE_URL';
const SUPABASE_KEY = 'PLACEHOLDER_SUPABASE_KEY';
const client = $('Boucle Clients').first().json;
const headers = { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` };

const today = new Date();
const todayStr = today.toISOString().split('T')[0];
const limit = new Date(today);
limit.setDate(today.getDate() + 2);
const limitStr = limit.toISOString().split('T')[0];

// Slots des prochaines 48h sans dossier Drive cree
let slots = [];
try {
  slots = await httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/editorial_slots?client_id=eq.${client.id}&scheduled_date=gte.${todayStr}&scheduled_date=lte.${limitStr}&drive_subfolder_id=is.null&order=scheduled_date.asc,scheduled_time.asc&select=id,scheduled_date,scheduled_time,content_type,category,theme,angle,tone,visual_direction,sublimation_mode,caption_style,objective`,
    headers
  });
} catch(e) {}

if (!slots || slots.length === 0) return [{ json: { _noSlots: true } }];

// Exclure les slots deja en production
let covered = [];
try {
  const ids = slots.map(s => s.id).join(',');
  covered = await httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/content_queue?slot_id=in.(${ids})&select=slot_id`,
    headers
  });
} catch(e) {}
const coveredIds = new Set((covered || []).map(c => c.slot_id));
const need = slots.filter(s => !coveredIds.has(s.id));

if (need.length === 0) return [{ json: { _noSlots: true } }];

return [{ json: {
  _noSlots: false,
  client_id: client.id,
  client_name: client.name,
  client_slug: client.slug,
  drive_folder_id: client.drive_folder_id,
  slots: need
}}];

const data = $input.first().json;
const slots = data.slots;
return slots.map(s => ({
  json: {
    ...s,
    client_id: data.client_id,
    client_name: data.client_name,
    client_slug: data.client_slug,
    drive_folder_id: data.drive_folder_id,
    subfolder_name: s.scheduled_date + '_' + (s.theme || 'sans-theme').toLowerCase().replace(/[^a-z0-9\u00e0\u00e2\u00e4\u00e9\u00e8\u00ea\u00eb\u00ef\u00ee\u00f4\u00f9\u00fb\u00fc\u00ff\u00e7]+/g, '-').replace(/(^-|-$)/g, '').substring(0, 50)
  }
}));

const httpRequest = globalThis.helpers.httpRequest;
const SUPABASE_URL = 'PLACEHOLDER_SUPABASE_URL';
const SUPABASE_KEY = 'PLACEHOLDER_SUPABASE_KEY';
const headers = {
  apikey: SUPABASE_KEY,
  Authorization: `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  Prefer: 'return=minimal'
};

const slot = $('Boucle Slots').first().json;
const driveResponse = $input.first().json;
const folderId = driveResponse.id;

await httpRequest({
  method: 'PATCH',
  url: `${SUPABASE_URL}/rest/v1/editorial_slots?id=eq.${slot.id}`,
  headers,
  body: JSON.stringify({
    drive_subfolder_id: folderId,
    photo_requested_at: new Date().toISOString()
  })
});

return [{
  json: {
    slot_id: slot.id,
    scheduled_date: slot.scheduled_date,
    scheduled_time: slot.scheduled_time,
    theme: slot.theme,
    category: slot.category,
    content_type: slot.content_type,
    visual_direction: slot.visual_direction,
    subfolder_name: slot.subfolder_name,
    drive_folder_id: folderId,
    drive_folder_url: `https://drive.google.com/drive/folders/${folderId}`
  }
}];

const processed = $('MAJ Slot Notifie').all();
const clientName = $('Charger Slots a Couvrir').first().json.client_name;

if (!processed || processed.length === 0) return [{ json: { _skip: true } }];

const jours = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];
const catLabels = {
  produit: 'Produit',
  coulisses: 'Coulisses',
  equipe: 'Equipe',
  engagement: 'Engagement',
  saisonnier: 'Saisonnier',
  educatif: 'Educatif',
  temoignage: 'Temoignage',
  ambiance: 'Ambiance'
};

const rows = processed.map(p => {
  const s = p.json;
  const d = new Date(s.scheduled_date + 'T12:00:00');
  const jour = jours[d.getDay()];
  const heure = (s.scheduled_time || '').substring(0, 5);
  const cat = catLabels[s.category] || s.category;
  const dir = s.visual_direction || '\u2014';
  return `<tr>\n    <td style=\"padding:12px 8px;border-bottom:1px solid #e5e7eb;\">${jour} ${s.scheduled_date} a ${heure}</td>\n    <td style=\"padding:12px 8px;border-bottom:1px solid #e5e7eb;\"><strong>${s.theme}</strong></td>\n    <td style=\"padding:12px 8px;border-bottom:1px solid #e5e7eb;\">${cat}</td>\n    <td style=\"padding:12px 8px;border-bottom:1px solid #e5e7eb;font-size:13px;color:#6b7280;\">${dir}</td>\n    <td style=\"padding:12px 8px;border-bottom:1px solid #e5e7eb;text-align:center;\"><a href=\"${s.drive_folder_url}\" style=\"display:inline-block;background:#0d9488;color:white;padding:6px 14px;border-radius:6px;text-decoration:none;font-size:13px;font-weight:600;\">Deposer</a></td>\n  </tr>`;
}).join('');

const html = `<div style=\"font-family:'Plus Jakarta Sans',Helvetica,Arial,sans-serif;max-width:720px;margin:0 auto;\">\n  <div style=\"background:#0d9488;padding:24px 28px;border-radius:12px 12px 0 0;\">\n    <h1 style=\"color:white;margin:0;font-size:20px;font-weight:700;\">Photos requises \u2014 ${clientName}</h1>\n    <p style=\"color:rgba(255,255,255,0.85);margin:8px 0 0;font-size:14px;\">${processed.length} creneau(x) dans les prochaines 48h</p>\n  </div>\n  <div style=\"background:#ffffff;padding:24px 28px;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 12px 12px;\">\n    <p style=\"color:#374151;margin:0 0 20px;font-size:15px;\">Bonjour, voici les creneaux editoriaux qui necessitent une photo. Cliquez sur <strong>Deposer</strong> pour ouvrir le sous-dossier Drive correspondant.</p>\n    <table style=\"width:100%;border-collapse:collapse;font-size:14px;\">\n      <thead><tr style=\"background:#f9fafb;\">\n        <th style=\"padding:10px 8px;text-align:left;border-bottom:2px solid #e5e7eb;font-weight:600;\">Publication</th>\n        <th style=\"padding:10px 8px;text-align:left;border-bottom:2px solid #e5e7eb;font-weight:600;\">Theme</th>\n        <th style=\"padding:10px 8px;text-align:left;border-bottom:2px solid #e5e7eb;font-weight:600;\">Categorie</th>\n        <th style=\"padding:10px 8px;text-align:left;border-bottom:2px solid #e5e7eb;font-weight:600;\">Direction visuelle</th>\n        <th style=\"padding:10px 8px;text-align:center;border-bottom:2px solid #e5e7eb;font-weight:600;\">Action</th>\n      </tr></thead>\n      <tbody>${rows}</tbody>\n    </table>\n    <p style=\"color:#9ca3af;font-size:12px;margin:24px 0 0;text-align:center;\">Neurolia Social Engine \u2014 notification automatique</p>\n  </div>\n</div>`;

return [{ json: {
  to: 'PLACEHOLDER_NOTIFICATION_EMAIL',
  subject: `Photos requises \u2014 ${clientName} (${processed.length} creneaux)`,
  html
}}];
